tests.test_body:
define i1 @or_and1(i1 %a, i1 %b, i1 %c) !prof !0 {
  %notb = xor i1 %b, true
  %cond = and i1 %notb, %c
  %r = select i1 %cond, i1 %a, i1 %b, !prof !1
  ret i1 %r
}

!0 = !{!"function_entry_count", i64 1000}
!1 = !{!"branch_weights", i32 2, i32 3}

define i1 @and_or2(i1 %a, i1 %b, i1 %c) !prof !0 {
  %notc = xor i1 %c, true
  %cond = and i1 %notc, %b
  %r = select i1 %cond, i1 %a, i1 %b, !prof !1
  ret i1 %r
}

!0 = !{!"function_entry_count", i64 1000}
!1 = !{!"branch_weights", i32 2, i32 3}

define i1 @fold_or_of_ands_with_select_to_logical2(i1 %a, i1 %b, i1 %c) !prof !0 {
  %not = xor i1 %c, true
  %and1 = and i1 %c, %a
  %and2 = select i1 %b, i1 %not, i1 false, !prof !1
  %or1 = or i1 %and1, %and2
  ret i1 %or1
}

!0 = !{!"function_entry_count", i64 1000}
!1 = !{!"branch_weights", i32 2, i32 3}

define i1 @and_or1(i1 %a, i1 %b, i1 %c) !prof !0 {
  %nota = xor i1 %a, true
  %cond = or i1 %nota, %c
  %r = select i1 %cond, i1 %a, i1 %b, !prof !1
  ret i1 %r
}

!0 = !{!"function_entry_count", i64 1000}
!1 = !{!"branch_weights", i32 2, i32 3}

@g1 = external global i16
@g2 = external global i16

define i1 @demorgan_select_infloop2(i1 %L) {
  %not.L = xor i1 %L, true
  %cmp1 = icmp eq ptr getelementptr inbounds (i16, ptr @g1, i64 1), @g1
  %cmp2 = icmp eq ptr getelementptr inbounds (i16, ptr @g2, i64 1), @g1
  %add = add i1 %cmp1, %cmp2
  %xor = xor i1 %add, true
  %C15 = select i1 %not.L, i1 %xor, i1 false
  ret i1 %C15
}

define i1 @and_or3_wrong_operand(i1 %a, i1 %b, i32 %x, i32 %y, i1 %d) {
  %c = icmp eq i32 %x, %y
  %cond = and i1 %b, %c
  %r = select i1 %cond, i1 %a, i1 %d
  ret i1 %r
}

define i1 @or_and3_wrong_operand(i1 %a, i1 %b, i32 %x, i32 %y, i1 %d) {
  %c = icmp eq i32 %x, %y
  %cond = or i1 %a, %c
  %r = select i1 %cond, i1 %d, i1 %b
  ret i1 %r
}

define i1 @fold_or_of_ands_with_select_to_logical1(i1 %a, i1 %b, i1 %c) !prof !0 {
  %not = xor i1 %c, true
  %and1 = and i1 %c, %a
  %and2 = select i1 %not, i1 %b, i1 false, !prof !1
  %or1 = or i1 %and1, %and2
  ret i1 %or1
}

!0 = !{!"function_entry_count", i64 1000}
!1 = !{!"branch_weights", i32 2, i32 3}

define i8 @test_or_umax(i8 %x, i8 %y, i1 %cond) !prof !0 {
  %cmp = icmp ugt i8 %x, %y
  %or = select i1 %cond, i1 true, i1 %cmp
  %ret = select i1 %or, i8 %x, i8 %y, !prof !1
  ret i8 %ret
}

!0 = !{!"function_entry_count", i64 1000}
!1 = !{!"branch_weights", i32 3, i32 2}

define i8 @test_logical_commuted_and_ne_a_b(i1 %other_cond, i8 %a, i8 %b) {
  %cmp = icmp ne i8 %a, %b
  %or.cond = select i1 %cmp, i1 %other_cond, i1 false
  %select = select i1 %or.cond, i8 %a, i8 %b
  ret i8 %select
}

define i1 @or_and2(i1 %a, i1 %b, i1 %c) !prof !0 {
  %notc = xor i1 %c, true
  %cond = or i1 %notc, %a
  %r = select i1 %cond, i1 %a, i1 %b, !prof !1
  ret i1 %r
}

!0 = !{!"function_entry_count", i64 1000}
!1 = !{!"branch_weights", i32 2, i32 3}
